class Solution {
    public String discountPrices(String sentence, int discount) {
        String[] words = sentence.split(" ");
        double discountFactor = (100 - (double) discount) / 100.0;
        for (int i = 0; i < words.length; i++) {
            if (words[i].startsWith("$") && words[i].substring(1).matches("\\d+")) {
                int price = Integer.parseInt(words[i].substring(1));
                double discountedPrice = price * discountFactor;
                words[i] = String.format("$%.2f", discountedPrice);
            }
        }
        return String.join(" ", words);
    }
}
